BOLD = "\033[1m" if _USE_COLOR else ""
DIM = "\033[2m" if _USE_COLOR else ""
NC = "\033[0m" if _USE_COLOR else ""

_ANSI_RE = re.compile(r"\033\[[0-9;]*m")

