def show_success_banner(
    ui: UI,
    platform_status: str,
    features: list[str],
    is_reinstall: bool = False,
    backend_results: list[dict[str, object]] | None = None,
) -> None:
    """Display the post-install success banner with summary.

    Content adapts to fresh vs. reinstall scenarios, shows real backend
    connectivity, and includes a random tip to teach users capabilities.
    """
    if ui.quiet:
        ui.info(f"TRW Framework v{TRW_VERSION} installed.")
        return

    if ui.interactive:
        print()
        draw_box(
            [f"{GREEN}{BOLD}\u2713 TRW Framework v{TRW_VERSION} \u2014 ready{NC}"],
            color=GREEN,
        )
        print()

        # Backend connectivity (real health check results)
        if backend_results:
            for br in backend_results:
                url = str(br["url"])
                # Friendly label for known URLs
                if "localhost" in url or "127.0.0.1" in url:
                    label = f"Local backend ({url})"
                elif "trwframework.com" in url:
                    label = "trwframework.com"
                else:
                    label = url
                if br["reachable"]:
                    print(f"  {GREEN}\u2022{NC} {label}")
                else:
                    print(f"  {DIM}\u2022 {label} (unreachable){NC}")
        elif platform_status == "connected":
            print(f"  {DIM}\u2022 API key configured (backend not verified){NC}")
        elif platform_status == "telemetry":
            print(f"  {BLUE}\u2022{NC} Anonymous telemetry enabled")
        else:
            print(f"  {DIM}\u2022 Offline mode (re-run installer to connect){NC}")

        if features:
            feat_str = ", ".join(features)
            print(f"  {DIM}Extras: {feat_str}{NC}")
        print()

        # Dynamic next-steps based on install type
        if is_reinstall:
            print(f"  {BOLD}After updating:{NC}")
            print(f"    {CYAN}\u2022{NC} Active MCP servers have been signaled to restart")
            print(f"    {CYAN}\u2022{NC} Run {BOLD}/mcp{NC} in Claude Code if tools aren't loading")
            print(f"    {CYAN}\u2022{NC} Your prior learnings carry forward automatically")
        else:
            print(f"  {BOLD}Get started:{NC}")
            print(f"    {CYAN}1.{NC} Open your project in Claude Code:  {BOLD}claude{NC}")
            print(f"    {CYAN}2.{NC} TRW tools load automatically \u2014 just start working")
            print(f"    {CYAN}3.{NC} Call {BOLD}trw_session_start(){NC} for context from prior sessions")

        # Random tip
        print()
        tip = random.choice(_TIPS)  # noqa: S311 — not security-sensitive
        print(f"  {DIM}\u25b8 Tip: {tip}{NC}")

        print()
        print(f"  {DIM}Upgrade anytime: python3 install-trw.py --upgrade{NC}")
        print(f"  {DIM}Full docs: {DOCS_BASE}/integration{NC}")
    else:
        print()
        print(f"{GREEN}{BOLD}TRW Framework v{TRW_VERSION} \u2014 ready{NC}")
        print()
        if backend_results:
            for br in backend_results:
                status = "ok" if br["reachable"] else "unreachable"
                ui.info(f"Backend {br['url']}: {status}")
        if is_reinstall:
            ui.info("Updated. MCP servers signaled to restart.")
        else:
            ui.info("Next: open your project in Claude Code \u2014 TRW tools load automatically.")
        ui.info(f"Docs: {DOCS_BASE}/integration")


# ── IDE detection and selection ──────────────────────────────────────


def _detect_installed_clis() -> list[str]:
    """Detect which AI coding CLI binaries are on PATH."""
    detected = []
    if shutil.which("claude"):
        detected.append("claude-code")
    if shutil.which("opencode"):
        detected.append("opencode")
    if shutil.which("codex"):
        detected.append("codex")
    return detected


def _detect_project_ides(project_dir: str) -> list[str]:
    """Detect which IDE configs exist in the project."""
    import os as _os

    detected = []
    if _os.path.isdir(_os.path.join(project_dir, ".claude")):
        detected.append("claude-code")
    if _os.path.isdir(_os.path.join(project_dir, ".opencode")) or _os.path.isfile(
        _os.path.join(project_dir, "opencode.json")
    ):
        detected.append("opencode")
    if _os.path.isdir(_os.path.join(project_dir, ".codex")) or _os.path.isfile(
        _os.path.join(project_dir, ".codex", "config.toml")
    ):
        detected.append("codex")
    return detected


def _prompt_ide_selection(detected_clis: list[str], detected_ides: list[str]) -> str | None:
    """Prompt user to select which IDE(s) to configure.

    Returns: "claude-code", "opencode", "codex", "all", or None (skip).
    """
    # Show what was detected
    if detected_clis:
        print(f"{GREEN}[TRW]{NC} Detected CLI(s): {', '.join(detected_clis)}")
    if detected_ides:
        print(f"{GREEN}[TRW]{NC} Existing IDE config: {', '.join(detected_ides)}")

    # Build options list: key, label, value
    options: list[tuple[str, str, str | None]] = []
    has_claude = "claude-code" in detected_clis or "claude-code" in detected_ides
    has_opencode = "opencode" in detected_clis or "opencode" in detected_ides
    has_codex = "codex" in detected_clis or "codex" in detected_ides

    if has_claude:
        options.append(("1", "Claude Code only", "claude-code"))
    if has_opencode:
        key = "2" if has_claude else "1"
        options.append((key, "OpenCode only", "opencode"))
    if has_codex:
        key = str(len(options) + 1)
        options.append((key, "Codex only", "codex"))

    # Always offer "all detected/current" and "skip"
    both_key = str(len(options) + 1)
    options.append((both_key, "All supported IDEs", "all"))
    skip_key = "s"
    options.append((skip_key, "Skip (configure later)", None))

    print("\nConfigure TRW for:")
    for key, label, _ in options:
        print(f"  [{key}] {label}")

    default_key = options[0][0]
    tty = _open_tty()
    if tty is None:
        return options[0][2]
    try:
        sys.stdout.write(f"\nSelection [default: {default_key}]: ")
        sys.stdout.flush()
        choice = tty.readline().strip().lower() or default_key
    finally:
        tty.close()

    for key, _, value in options:
        if choice == key:
            return value
    return options[0][2]  # default to first option


# ── Find trw-mcp command ─────────────────────────────────────────────


def find_trw_cmd(python: str, pip_target: str = "") -> list[str]:
    """Return the command list for invoking trw-mcp CLI."""
    validated_target = validate_pip_target(pip_target)
    if validated_target:
        wrapper = Path(validated_target) / "bin" / "trw-mcp"
        if wrapper.is_file():
            return [str(wrapper)]
    if shutil.which("trw-mcp"):
        return ["trw-mcp"]
    return [python, "-B", "-m", "trw_mcp.server"]


# ── Installation phases ──────────────────────────────────────────────


def phase_extract_wheels(ui: UI, step: int, total: int, tmpdir: Path) -> tuple[Path, Path]:
    """Phase 2: Extract embedded wheel files."""
    ui.step_header(step, total, "Extracting embedded packages")
    ui.start_spinner("Extracting wheels...")
    try:
        memory_whl, mcp_whl = extract_wheels(tmpdir)
        ok = memory_whl.stat().st_size > 0 and mcp_whl.stat().st_size > 0
    except Exception as exc:
        ui.stop_spinner(False, "", f"Failed to extract wheels: {exc}")
        sys.exit(1)
    ui.stop_spinner(ok, "Extracted trw-memory and trw-mcp wheels")
    if not ok:
        ui.step_fail("Extracted wheels are empty")
        sys.exit(1)
    return memory_whl, mcp_whl


def phase_prompt_features(
    ui: UI,
    install_ai: bool | None,
    install_sqlitevec: bool | None,
    prior_extras: dict[str, bool] | None = None,
) -> tuple[bool, bool]:
    """Prompt for optional features (interactive only). Skips if already answered.

    When both extras are already configured (prior install or CLI flags),
    shows a compact summary line instead of the full prompt section.
    """
    if prior_extras is None:
        prior_extras = {}

    ai_configured = prior_extras.get("ai", False)
    vec_configured = prior_extras.get("sqlite_vec", False)

    # Both already determined via CLI flags — nothing to show
    if install_ai is not None and install_sqlitevec is not None:
        return bool(install_ai), bool(install_sqlitevec)

    # Both from prior install — compact one-liner, no prompts
    if ai_configured and vec_configured and install_ai is None and install_sqlitevec is None:
        names = []
        if ai_configured:
            names.append("AI/LLM")
        if vec_configured:
            names.append("sqlite-vec")
        print(f"  {GREEN}\u2713{NC} Extras: {', '.join(names)} (from prior install)")
        return True, True

    # Need to prompt for at least one — show the feature section
    draw_divider("Optional Features")

    if install_ai is None:
        if ai_configured:
            print(f"  {GREEN}\u2713{NC} AI extras (from prior install)")
            install_ai = True
        else:
            print()
            ui.hint("AI extras enable semantic search over your learnings")
            ui.hint("and LLM-powered analysis of patterns across sessions.")
            ui.doc_link("integration#ai-extras")
            install_ai = prompt_yes_no("Install AI/LLM features?")

    if install_sqlitevec is None:
        if vec_configured:
            print(f"  {GREEN}\u2713{NC} sqlite-vec (from prior install)")
            install_sqlitevec = True
        else:
            print()
            ui.hint("sqlite-vec adds vector similarity search for faster,")
            ui.hint("more relevant recall of past learnings and discoveries.")
            ui.doc_link("integration#vector-search")
            install_sqlitevec = prompt_yes_no("Install sqlite-vec for vector search?")

    return bool(install_ai), bool(install_sqlitevec)


def phase_install_packages(
    ui: UI,
    step: int,
    total: int,
    python: str,
    memory_whl: Path,
    mcp_whl: Path,
    pip_target: str = "",
) -> None:
    """Phase 3: Install base packages (order: memory -> mcp).

    When *pip_target* is set, passes ``--target`` to pip so all packages
    are written to that directory (e.g. a tmpfs mount) instead of
    site-packages.  A PYTHONPATH wrapper is generated under
    ``<pip-target>/bin/trw-mcp`` so the CLI finds the packages at runtime
    without writing to overlay-backed system paths.
    """
    ui.step_header(step, total, "Installing packages")
    validated_target = validate_pip_target(pip_target)

    ui.start_spinner("Installing trw-memory...")
    if not pip_install(python, str(memory_whl), "trw-memory", ui, target_dir=validated_target):
        ui.stop_spinner(False, "", "pip install failed for trw-memory")
        ui.error("Try installing in a virtual environment:")
        ui.error("  python3 -m venv .venv && source .venv/bin/activate")
        ui.error("  python3 install-trw.py")
        sys.exit(1)
    ui.stop_spinner(True, "Installed trw-memory")

    ui.start_spinner(f"Installing trw-mcp v{TRW_VERSION}...")
    if not pip_install(python, str(mcp_whl), "trw-mcp", ui, target_dir=validated_target):
        ui.stop_spinner(False, "", "pip install failed for trw-mcp")
        ui.error("Try installing in a virtual environment:")
        ui.error("  python3 -m venv .venv && source .venv/bin/activate")
        ui.error("  python3 install-trw.py")
        sys.exit(1)
    ui.stop_spinner(True, f"Installed trw-mcp v{TRW_VERSION}")

    # When using --pip-target, generate a PYTHONPATH wrapper (FR04)
    if validated_target:
        wrapper = Path(validated_target) / "bin" / "trw-mcp"
        wrapper.parent.mkdir(parents=True, exist_ok=True)
        wrapper.write_text(
            f"#!/bin/bash\n"
            f"export PYTHONPATH={validated_target}:$PYTHONPATH\n"
            f'exec {python} -B -c "from trw_mcp.server import main; main()" "$@"\n'
        )
        wrapper.chmod(0o755)
        ui.info(f"PYTHONPATH wrapper: {wrapper} -> {validated_target}")

    # Verify imports (set PYTHONPATH for --pip-target case)
    env = _build_pip_runtime_env(validated_target)
    if validated_target:
        current_path = env.get("PYTHONPATH", "")
        env["PYTHONPATH"] = f"{validated_target}:{current_path}" if current_path else validated_target
    for mod in ("trw_memory", "trw_mcp"):
        rc = subprocess.run(
            [python, "-B", "-c", f"import {mod}"],
            env=env,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
        ).returncode
        if rc != 0:
            ui.step_fail(f"{mod} not importable after install")
            sys.exit(1)


def phase_install_extras(
    ui: UI,
    step: int,
    total: int,
    python: str,
    install_ai: bool,
    install_sqlitevec: bool,
    pip_target: str = "",
) -> list[str]:
    """Install optional extras as a single step. Returns feature names."""
    ui.step_header(step, total, "Installing extras")
    features: list[str] = []
    validated_target = validate_pip_target(pip_target)

    if install_ai:
        ui.start_spinner("Installing trw-mcp[ai]...")
        ok = pip_install(python, "trw-mcp[ai]", "trw-mcp[ai]", ui, target_dir=validated_target)
        ui.stop_spinner(ok, "AI features enabled", "AI extras failed (non-fatal)")
        if ok:
            features.append("AI/LLM")
        else:
            ui.step_warn("AI extras failed \u2014 base TRW still works fine")

        ui.start_spinner("Installing sentence-transformers (embeddings)...")
        ok = pip_install(
            python,
            "sentence-transformers>=2.0.0",
            "sentence-transformers",
            ui,
            target_dir=validated_target,
        )
        ui.stop_spinner(ok, "Embeddings enabled", "Embeddings install failed (non-fatal)")
        if ok:
            features.append("embeddings")
        else:
            ui.step_warn("sentence-transformers failed \u2014 recall uses keyword-only search")

    if install_sqlitevec:
        ui.start_spinner("Installing sqlite-vec...")
        ok = pip_install(python, "sqlite-vec", "sqlite-vec", ui, target_dir=validated_target)
        ui.stop_spinner(ok, "sqlite-vec enabled", "sqlite-vec failed (non-fatal)")
        if ok:
            features.append("sqlite-vec")
        else:
            ui.step_warn("sqlite-vec failed \u2014 TRW works without it")

    return features


def phase_project_setup(
    ui: UI,
    step: int,
    total: int,
    python: str,
    target_dir: Path,
    upgrade_only: bool,
    interactive: bool = False,
    ide: str | None = None,
    pip_target: str = "",
) -> None:
    """Set up or update the project scaffolding."""
    ui.step_header(step, total, "Setting up project")

    if upgrade_only:
        ui.step_ok("Upgrade complete — skipping project setup")
        return

    if not (target_dir / ".git").is_dir():
        ui.step_warn("Not a git repository — skipping project setup")
        ui.step_warn("After git init, run: trw-mcp init-project .")
        return

    # IDE detection and selection
    detected_clis = _detect_installed_clis()
    detected_ides = _detect_project_ides(str(target_dir))

    resolved_ide: str | None = ide
    is_update = (target_dir / ".trw").is_dir()
    if resolved_ide is None:
        if is_update and interactive and detected_ides:
            # Re-run: use previously configured IDEs without prompting
            resolved_ide = "all" if len(detected_ides) >= 2 else detected_ides[0]
            ui.step_ok(f"IDE config: {', '.join(detected_ides)} (from prior install)")
        elif interactive:
            resolved_ide = _prompt_ide_selection(detected_clis, detected_ides)
        else:
            # Headless: auto-configure all detected CLIs; default to claude-code if none
            all_detected = list(dict.fromkeys(detected_clis + detected_ides))
            if len(all_detected) >= 2:
                resolved_ide = "all"
            elif len(all_detected) == 1:
                resolved_ide = all_detected[0]
            else:
                resolved_ide = "claude-code"

    trw_cmd = find_trw_cmd(python, pip_target=pip_target)
    action = "update-project" if is_update else "init-project"
    label = "Updating" if is_update else "Initializing"

    cmd = trw_cmd + [action, str(target_dir)]
    if resolved_ide is not None:
        cmd += ["--ide", resolved_ide]

    ok = run_with_progress(ui, f"{label} project...", cmd)
    ui.stop_spinner(ok, f"Project {'updated' if is_update else 'initialized'}", f"Project {action} failed")

    # Generate per-client instruction files after project setup
    # (FR01, FR02, FR03: Split AGENTS.md into per-client instruction files)
    if resolved_ide in ("all", "opencode", "codex"):
        _generate_per_client_instructions(
            ui,
            target_dir,
            resolved_ide,
            is_update,
            python,
            pip_target=pip_target,
        )


def phase_configure(
    ui: UI,
    step: int,
    total: int,
    target_dir: Path,
    interactive: bool,
    opt_name: str,
    opt_api_key: str,
    opt_telemetry: bool | None,
    prior_config: dict[str, object] | None = None,
    *,
    install_ai: bool = False,
    install_vec: bool = False,
    skip_auth: bool = False,
) -> str:
    """Configure project identity, API key, and telemetry. Returns platform_status."""
    ui.step_header(step, total, "Configure your project")

    if prior_config is None:
        prior_config = {}

    default_name = sanitize_project_name(target_dir.name)
    project_name = ""
    api_key = ""
    telemetry_enabled = False

    if interactive:
        if prior_config.get("project_name"):
            project_name = str(prior_config["project_name"])
            ui.step_ok(f"Project: {project_name} (from prior install)")
        else:
            draw_divider("Project Identity")
            print()
            ui.hint("This name identifies your installation in the TRW platform.")
            ui.hint("It appears in your analytics dashboard and team views.")
            project_name = _prompt_project_name(ui, default_name)

        if prior_config.get("api_key"):
            ui.step_ok("API key: configured (from prior install)")
            api_key = str(prior_config["api_key"])
            telemetry_enabled = True
        elif skip_auth and opt_api_key and validate_api_key(opt_api_key):
            api_key = opt_api_key
            telemetry_enabled = True
            ui.step_ok("API key: accepted (from bootstrap)")
        elif skip_auth:
            ui.step_ok("Auth skipped (--skip-auth)")
        else:
            draw_divider("Platform Connection")
            print()
            ui.hint("Connect to trwframework.com to sync learnings across")
            ui.hint("machines, view analytics, and collaborate with your team.")
            ui.doc_link("integration#platform-connection")
            api_key = _prompt_api_key(ui)

            if api_key:
                telemetry_enabled = True
            elif "telemetry" in prior_config:
                telemetry_enabled = bool(prior_config["telemetry"])
                ui.step_ok(f"Telemetry: {'enabled' if telemetry_enabled else 'disabled'} (from prior install)")
            else:
                print()
                ui.hint("Anonymous telemetry helps us improve TRW for everyone.")
                ui.hint("Only tool usage counts are shared — no code or learnings.")
                ui.doc_link("integration#telemetry")
                telemetry_enabled = prompt_yes_no("Enable anonymous usage telemetry?")
                ui.step_ok("Telemetry enabled" if telemetry_enabled else "Telemetry disabled")
    else:
        # Script mode: use flags
        project_name = sanitize_project_name(opt_name) if opt_name else default_name
        # PRD-FIX-067-FR02: Check prior_config before opt_api_key
        if prior_config.get("api_key"):
            api_key = str(prior_config["api_key"])
            telemetry_enabled = True
            ui.step_ok("API key: configured (from prior install)")
        elif opt_api_key:
            if validate_api_key(opt_api_key):
                api_key = opt_api_key
                telemetry_enabled = True
            else:
                ui.warn("Invalid API key format — ignoring --api-key")
        if not api_key and opt_telemetry is True:
            telemetry_enabled = True
        if opt_telemetry is False:
            telemetry_enabled = False
        ui.step_ok(f"Project: {project_name}")

    # Write to config (including feature flags for future reinstall detection)
    config_path = target_dir / ".trw" / "config.yaml"
    if update_config(
        config_path,
        project_name,
        api_key,
        telemetry_enabled,
        embeddings_enabled=install_ai or None,
        sqlite_vec_enabled=install_vec or None,
    ):
        ui.step_ok("Configuration saved to .trw/config.yaml")
    else:
        ui.step_warn("Config file not found — run project setup first")

    if api_key:
        return "connected"
    if telemetry_enabled:
        return "telemetry"
    return "offline"


def _prompt_project_name(ui: UI, default: str) -> str:
    """Interactive project name prompt with sanitization."""
    raw = prompt_input("Project name:", default)
    name = sanitize_project_name(raw)
    if not name:
        name = default
    if not re.match(r"^[a-z0-9]([a-z0-9-]*[a-z0-9])?$", name):
        ui.step_warn("Could not sanitize name, using default")
        name = default
    if name != raw and raw:
        ui.step_ok(f"Project name: {name} (sanitized from '{raw}')")
    else:
        ui.step_ok(f"Project name: {name}")
    return name


def _prompt_api_key(ui: UI) -> str:
    """Interactive API key prompt -- tries device auth first, falls back to manual paste.

    Device authorization (RFC 8628) opens a browser for passwordless login.
    If device auth is unavailable or user declines, falls back to manual key entry.
    """
    # Try device auth flow first
    try:
        result = _device_auth_login(DOCS_BASE.replace("/docs", ""), interactive=True)
        if result and isinstance(result.get("api_key"), str) and result["api_key"]:
            key = str(result["api_key"])
            if validate_api_key(key):
                ui.step_ok("Authenticated via device flow")
                return key
    except Exception:  # device auth is best-effort, fall back to manual
        pass

    # Fallback: manual key entry
    print()
    ui.hint("Or paste an API key manually:")
    max_attempts = 3
    for attempt in range(max_attempts):
        raw = prompt_input("Platform API key (Enter to skip):").strip()
        if not raw:
            ui.step_ok("No API key -- offline mode")
            return ""
        if validate_api_key(raw):
            ui.step_ok("API key accepted")
            return raw
        remaining = max_attempts - attempt - 1
        if remaining > 0:
            ui.step_warn("Invalid format (must start with trw_, alphanumeric only). Try again:")
        else:
            ui.step_warn("Invalid format -- skipping API key")
    return ""


def _device_auth_login(api_url: str, interactive: bool = True) -> dict | None:
    """Perform RFC 8628 device authorization -- stdlib only.

    Inline implementation that avoids importing trw_mcp.cli.auth (which may
    not be installed when running the standalone installer script).
    """
    import json as _json
    import time as _time
    import urllib.error
    import urllib.request
    import webbrowser as _wb

    api_url = api_url.rstrip("/")

    # Step 1: Request device code
    try:
        body = _json.dumps({"client_id": "trw-cli"}).encode("utf-8")
        req = urllib.request.Request(
            f"{api_url}/v1/auth/device/code",
            data=body,
            method="POST",
            headers={"Content-Type": "application/json"},
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            code_resp = _json.loads(resp.read().decode("utf-8"))
    except (urllib.error.URLError, OSError):
        return None

    device_code = code_resp.get("device_code", "")
    user_code = code_resp.get("user_code", "")
    verification_uri = code_resp.get("verification_uri", "")
    verification_uri_complete = code_resp.get("verification_uri_complete", verification_uri)
    interval = int(str(code_resp.get("interval", 5)))
    expires_in = int(str(code_resp.get("expires_in", 900)))

    if not device_code or not user_code:
        return None

    # Step 2: Display URL immediately, then try browser in background thread
    if interactive:
        print()
        print(f"  {BOLD}Open this URL to authenticate:{NC}")
        print()
        print(f"    {GREEN}{verification_uri_complete}{NC}")
        print()

        def _open_bg() -> None:
            try:
                _wb.open(verification_uri_complete)
            except Exception:
                pass

        _t = threading.Thread(target=_open_bg, daemon=True)
        _t.start()
        _t.join(timeout=2.0)
        if not _t.is_alive():
            print(f"  {DIM}(Browser opened \u2014 verify the code matches){NC}")
        else:
            print(f"  {DIM}(Opening browser...){NC}")

    # Step 3: Poll for token
    deadline = _time.monotonic() + expires_in
    poll_interval = interval

    while _time.monotonic() < deadline:
        _time.sleep(poll_interval)
        try:
            body = _json.dumps(
                {
                    "client_id": "trw-cli",
                    "device_code": device_code,
                    "grant_type": "urn:ietf:params:oauth:grant-type:device_code",
                }
            ).encode("utf-8")
            req = urllib.request.Request(
                f"{api_url}/v1/auth/device/token",
                data=body,
                method="POST",
                headers={"Content-Type": "application/json"},
            )
            with urllib.request.urlopen(req, timeout=10) as resp:
                return _json.loads(resp.read().decode("utf-8"))
        except urllib.error.HTTPError as exc:
            err_code = ""
            try:
                err_body = _json.loads(exc.read().decode("utf-8"))
                err_code = err_body.get("error", "")
            except Exception:
                pass
            if err_code == "authorization_pending":
                continue
            elif err_code == "slow_down":
                poll_interval += 5
                continue
            elif err_code in ("expired_token", "access_denied"):
                return None
            else:
                return None
        except (urllib.error.URLError, OSError):
            poll_interval = min(poll_interval * 2, 30)
            continue

    return None


# ── Per-client instruction file generation ────────────────────────────


def _generate_per_client_instructions(
    ui: UI,
    target_dir: Path,
    ide_selection: str,
    is_update: bool,
    python: str,
    pip_target: str = "",
) -> None:
    """Generate per-client instruction files for selected IDEs.

    Calls the TRW bootstrap functions to generate INSTRUCTIONS.md files
    optimized for each selected IDE's model family (qwen, gpt, claude).

    FR01, FR02, FR03: Split AGENTS.md into per-client instruction files
    FR06, FR07: Wire per-client instruction generation into installer
    """
    import subprocess

    trw_cmd = find_trw_cmd(python, pip_target=pip_target) + ["update-project", str(target_dir)]

    if ide_selection == "all":
        # Generate for all supported IDEs
        trw_cmd.extend(["--ide", "all"])
    else:
        trw_cmd.extend(["--ide", ide_selection])

    try:
        result = subprocess.run(
            trw_cmd,
            capture_output=True,
            text=True,
            timeout=60,
        )
        if result.returncode == 0:
            if is_update:
                ui.step_ok("Per-client instruction files updated")
            else:
                ui.step_ok("Per-client instruction files generated")
        else:
            ui.step_warn("Instruction file generation encountered warnings")
    except subprocess.TimeoutExpired:
        ui.step_warn("Instruction file generation timed out (may still be running)")
    except Exception as exc:
        ui.step_warn(f"Failed to generate per-client instruction files: {exc}")


# ── Main ─────────────────────────────────────────────────────────────


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Install TRW Framework in a project directory.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog=(
            "Interactive mode (default in a terminal):\n"
            "  Guided setup with prompts, spinners, and feature selection.\n\n"
            "Script mode (piped input or --script):\n"
            "  No prompts. Use flags to configure.\n\n"
            "Examples:\n"
            "  python3 install-trw.py                       # Interactive\n"
            "  python3 install-trw.py --ai --telemetry      # With extras\n"
            "  python3 install-trw.py --script --no-ai      # Headless\n"
            "  python3 install-trw.py --upgrade             # Upgrade only\n"
        ),
    )
    parser.add_argument("target_dir", nargs="?", default=".", help="Project directory")
    parser.add_argument("--upgrade", action="store_true", help="Upgrade package only")
    parser.add_argument("--ai", dest="install_ai", action="store_true", default=None, help="Install AI/LLM extras")
    parser.add_argument("--no-ai", dest="install_ai", action="store_false", help="Skip AI extras")
    parser.add_argument(
        "--sqlite-vec", dest="install_vec", action="store_true", default=None, help="Install sqlite-vec"
    )
    parser.add_argument("--no-sqlite-vec", dest="install_vec", action="store_false", help="Skip sqlite-vec")
    parser.add_argument("--quiet", "-q", action="store_true", help="Minimal output")
    parser.add_argument("--script", action="store_true", help="Force non-interactive mode")
    parser.add_argument("--name", default="", help="Project name (installation ID)")
    parser.add_argument("--api-key", default="", help="Platform API key")
    parser.add_argument("--telemetry", dest="telemetry", action="store_true", default=None, help="Enable telemetry")
    parser.add_argument("--no-telemetry", dest="telemetry", action="store_false", help="Disable telemetry")
    parser.add_argument("--skip-auth", action="store_true", help="Skip device auth flow during install")
    parser.add_argument(
        "--pip-target",
        default="",
        metavar="DIR",
        help="Install packages to DIR instead of site-packages (for tmpfs mounts)",
    )
    parser.add_argument(
        "--ide",
        choices=["claude-code", "opencode", "codex", "all"],
        default=None,
        help="Target IDE to configure (prompted if not specified in interactive mode)",
    )

    args = parser.parse_args()

    # Mode detection
    interactive = (not args.script) and sys.stdin.isatty()

    # Script-mode defaults
    install_ai = args.install_ai
    install_vec = args.install_vec
    if not interactive:
        install_ai = install_ai if install_ai is not None else False
        install_vec = install_vec if install_vec is not None else False

    # Resolve target
    target_dir = Path(args.target_dir).resolve()
    if not target_dir.is_dir():
        print(f"{RED}[TRW]{NC} Directory not found: {target_dir}", file=sys.stderr)
        sys.exit(1)

    ui = UI(interactive=interactive, quiet=args.quiet)

    show_banner(ui)

    # ── Preflight ────────────────────────────────────────────────────
    # Gather all information BEFORE showing numbered steps so the step
    # count never changes mid-flow.

    prior_config = _load_prior_config(target_dir)
    is_reinstall = bool(prior_config)

    if is_reinstall and interactive:
        ui.info("Existing TRW installation detected \u2014 reusing prior settings")

    if interactive:
        draw_divider("Preflight")

    # Python check (preflight — not a numbered step)
    python = check_python_version(ui)
    major, minor = sys.version_info[:2]
    if interactive:
        print(f"  {GREEN}\u2713{NC} Python {major}.{minor} ({python})")
    else:
        ui.info(f"Python {major}.{minor} ({python})")

    # Detect already-installed extras via runtime imports
    prior_extras: dict[str, bool] = _detect_installed_extras(python) if is_reinstall else {}
    # Also honour config-level feature flags (user's prior choice persists
    # even if the venv was recreated or packages temporarily missing)
    if prior_config.get("embeddings"):
        prior_extras.setdefault("ai", True)
    if prior_config.get("sqlite_vec"):
        prior_extras.setdefault("sqlite_vec", True)

    # Feature selection (interactive: prompt now; script: already resolved)
    if interactive:
        install_ai, install_vec = phase_prompt_features(
            ui,
            install_ai,
            install_vec,
            prior_extras=prior_extras,
        )

    install_ai = bool(install_ai)
    install_vec = bool(install_vec)
    has_extras = install_ai or install_vec
    has_config = interactive or args.name or args.api_key or bool(prior_config)

    # ── Step count (stable from here on) ─────────────────────────────
    total = 3  # extract + install + project-setup
    if has_extras:
        total += 1
    if has_config:
        total += 1

    # Create temp dir for wheel extraction
    tmpdir = Path(tempfile.mkdtemp(prefix="trw-install-"))
    try:
        step = 0

        # Step 1: Extract wheels
        step += 1
        memory_whl, mcp_whl = phase_extract_wheels(ui, step, total, tmpdir)

        # Step 2: Install base packages
        step += 1
        phase_install_packages(ui, step, total, python, memory_whl, mcp_whl, pip_target=args.pip_target)

        # Step 3 (conditional): Install extras
        features: list[str] = []
        if has_extras:
            step += 1
            features = phase_install_extras(
                ui,
                step,
                total,
                python,
                install_ai,
                install_vec,
                pip_target=args.pip_target,
            )

        # Step N: Project setup
        step += 1
        phase_project_setup(
            ui,
            step,
            total,
            python,
            target_dir,
            args.upgrade,
            interactive=interactive,
            ide=args.ide,
            pip_target=args.pip_target,
        )

        # Step N+1 (conditional): Configure
        platform_status = "offline"
        if has_config:
            step += 1
            platform_status = phase_configure(
                ui,
                step,
                total,
                target_dir,
                interactive,
                args.name,
                args.api_key,
                args.telemetry,
                prior_config=prior_config,
                install_ai=install_ai,
                install_vec=install_vec,
                skip_auth=getattr(args, "skip_auth", False),
            )

        # Post-install: restart MCP servers and health-check backends
        _restart_mcp_servers(target_dir, ui)

        backend_results: list[dict[str, object]] = []
        if (
            platform_status in ("connected", "telemetry")
            or (target_dir / "docker-compose.yml").is_file()
            or (target_dir / "docker-compose.yaml").is_file()
        ):
            if interactive:
                ui.start_spinner("Checking backend connectivity...")
            backend_results = _check_all_backends(target_dir, prior_config)
            if interactive:
                ui.stop_spinner(True, "Backend connectivity checked")

        # Done!
        show_success_banner(
            ui,
            platform_status,
            features,
            is_reinstall=is_reinstall,
            backend_results=backend_results,
        )

    finally:
        try:
            shutil.rmtree(tmpdir)
        except OSError:
            pass


if __name__ == "__main__":
    main()

